"use client";

import { useState } from "react";
import Link from "next/link";
import { Eye, EyeOff, Lock, Mail, ArrowRight } from "lucide-react";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { Label } from "@/components/ui/label";
import { Switch } from "@/components/ui/switch";

export default function LoginPage() {
    const [email, setEmail] = useState("");
    const [password, setPassword] = useState("");
    const [showPassword, setShowPassword] = useState(false);
    const [rememberMe, setRememberMe] = useState(false);

    const handleSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        // Mock login — redirect to dashboard
        window.location.href = "/";
    };

    return (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Logo & Welcome */}
            <div className="text-center space-y-2">
                <div className="inline-flex h-16 w-16 items-center justify-center rounded-2xl bg-primary text-3xl shadow-lg shadow-primary/30 mb-2">
                    🐷
                </div>
                <h1 className="text-2xl font-bold text-foreground tracking-tight">
                    Keuanganku
                </h1>
                <p className="text-sm text-muted-foreground">
                    Masuk untuk kelola keuanganmu ✨
                </p>
            </div>

            {/* Card */}
            <div className="rounded-3xl border border-primary/15 bg-white/80 backdrop-blur-sm p-7 shadow-xl shadow-primary/5">
                <form onSubmit={handleSubmit} className="space-y-5">
                    {/* Email */}
                    <div className="space-y-1.5">
                        <Label className="text-xs font-medium text-foreground">Email</Label>
                        <div className="relative">
                            <Mail className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                            <Input
                                type="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                placeholder="nama@email.com"
                                className="h-11 pl-9 rounded-xl border-primary/15 focus-visible:ring-primary/30 bg-white"
                                required
                            />
                        </div>
                    </div>

                    {/* Password */}
                    <div className="space-y-1.5">
                        <Label className="text-xs font-medium text-foreground">Kata Sandi</Label>
                        <div className="relative">
                            <Lock className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                            <Input
                                type={showPassword ? "text" : "password"}
                                value={password}
                                onChange={(e) => setPassword(e.target.value)}
                                placeholder="••••••••"
                                className="h-11 pl-9 pr-10 rounded-xl border-primary/15 focus-visible:ring-primary/30 bg-white"
                                required
                            />
                            <button
                                type="button"
                                onClick={() => setShowPassword(!showPassword)}
                                className="absolute right-3 top-1/2 -translate-y-1/2 text-muted-foreground hover:text-foreground transition-colors"
                            >
                                {showPassword ? (
                                    <EyeOff className="h-4 w-4" />
                                ) : (
                                    <Eye className="h-4 w-4" />
                                )}
                            </button>
                        </div>
                    </div>

                    {/* Remember & Forgot */}
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-2">
                            <Switch
                                id="remember"
                                checked={rememberMe}
                                onCheckedChange={setRememberMe}
                                className="scale-80"
                            />
                            <Label htmlFor="remember" className="text-xs text-muted-foreground cursor-pointer">
                                Ingat saya
                            </Label>
                        </div>
                        <button type="button" className="text-xs text-primary hover:underline font-medium">
                            Lupa kata sandi?
                        </button>
                    </div>

                    {/* Submit */}
                    <Button
                        type="submit"
                        className="w-full h-11 rounded-xl bg-primary hover:bg-primary/90 font-semibold text-sm group shadow-lg shadow-primary/25 transition-all"
                        disabled={!email || !password}
                    >
                        Masuk
                        <ArrowRight className="h-4 w-4 ml-1.5 group-hover:translate-x-0.5 transition-transform" />
                    </Button>
                </form>

                {/* Divider */}
                <div className="relative my-5">
                    <div className="absolute inset-0 flex items-center">
                        <div className="w-full border-t border-primary/10" />
                    </div>
                    <div className="relative flex justify-center">
                        <span className="bg-white/80 px-3 text-[11px] text-muted-foreground">atau</span>
                    </div>
                </div>

                {/* Social */}
                <Button
                    type="button"
                    variant="outline"
                    className="w-full h-11 rounded-xl border-primary/15 text-sm font-medium hover:bg-primary/5 transition-all"
                >
                    <svg className="h-4 w-4 mr-2" viewBox="0 0 24 24">
                        <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92a5.06 5.06 0 0 1-2.2 3.32v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.1z" fill="#4285F4" />
                        <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853" />
                        <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05" />
                        <path d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335" />
                    </svg>
                    Masuk dengan Google
                </Button>
            </div>

            {/* Footer */}
            <p className="text-center text-xs text-muted-foreground">
                Belum punya akun?{" "}
                <button className="text-primary hover:underline font-medium">
                    Daftar sekarang
                </button>
            </p>
        </div>
    );
}

"use client";

import { useState } from "react";
import { Plus, Bell, BellOff, Check, Calendar, Clock, RotateCcw } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { cn, formatCurrency, formatDate } from "@/lib/utils";
import { mockReminders } from "@/lib/mock-data";
import type { Reminder } from "@/types";

export default function RemindersPage() {
    const [reminders, setReminders] = useState<Reminder[]>(mockReminders);

    const toggleComplete = (id: string) => {
        setReminders((prev) =>
            prev.map((r) => (r.id === id ? { ...r, isCompleted: !r.isCompleted } : r))
        );
    };

    const upcoming = reminders.filter((r) => !r.isCompleted);
    const completed = reminders.filter((r) => r.isCompleted);

    function getDaysUntil(dateStr: string): number {
        const due = new Date(dateStr);
        const now = new Date("2026-02-17");
        return Math.ceil((due.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
    }

    function getUrgencyStyle(days: number) {
        if (days < 0) return { label: "Terlewat!", color: "bg-red-50 text-red-600 border-red-200" };
        if (days <= 3) return { label: `${days} hari lagi`, color: "bg-amber-50 text-amber-600 border-amber-200" };
        if (days <= 7) return { label: `${days} hari lagi`, color: "bg-blue-50 text-blue-600 border-blue-200" };
        return { label: `${days} hari lagi`, color: "bg-gray-50 text-gray-600 border-gray-200" };
    }

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            {/* Header */}
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
                <div>
                    <h2 className="text-xl font-bold text-foreground">
                        Pengingat 🔔
                    </h2>
                    <p className="text-sm text-muted-foreground mt-1">
                        {upcoming.length} pengingat aktif
                    </p>
                </div>
                <Button className="rounded-xl bg-primary hover:bg-primary/90 shadow-lg shadow-primary/25">
                    <Plus className="h-4 w-4 mr-1.5" />
                    Pengingat Baru
                </Button>
            </div>

            {/* Upcoming */}
            <div>
                <div className="flex items-center gap-2 mb-3">
                    <Bell className="h-4 w-4 text-primary" />
                    <h3 className="text-sm font-semibold text-foreground">Akan Datang</h3>
                </div>

                <div className="space-y-2">
                    {upcoming
                        .sort((a, b) => new Date(a.dueDate).getTime() - new Date(b.dueDate).getTime())
                        .map((reminder) => {
                            const days = getDaysUntil(reminder.dueDate);
                            const urgency = getUrgencyStyle(days);

                            return (
                                <div
                                    key={reminder.id}
                                    className="group flex items-center gap-3 rounded-2xl border border-primary/10 bg-white px-4 py-3 transition-all duration-200 hover:shadow-md hover:shadow-primary/5"
                                >
                                    {/* Check button */}
                                    <button
                                        onClick={() => toggleComplete(reminder.id)}
                                        className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full border-2 border-primary/30 text-primary/30 hover:bg-primary hover:text-white hover:border-primary transition-all"
                                    >
                                        <Check className="h-4 w-4" />
                                    </button>

                                    {/* Info */}
                                    <div className="flex-1 min-w-0">
                                        <p className="text-sm font-medium text-foreground">{reminder.title}</p>
                                        <div className="flex items-center gap-2 mt-0.5">
                                            <div className="flex items-center gap-1">
                                                <Calendar className="h-3 w-3 text-muted-foreground" />
                                                <span className="text-[11px] text-muted-foreground">
                                                    {formatDate(reminder.dueDate)}
                                                </span>
                                            </div>
                                            {reminder.isRecurring && (
                                                <div className="flex items-center gap-1">
                                                    <RotateCcw className="h-3 w-3 text-muted-foreground" />
                                                    <span className="text-[11px] text-muted-foreground">Bulanan</span>
                                                </div>
                                            )}
                                        </div>
                                    </div>

                                    {/* Urgency badge */}
                                    <Badge
                                        variant="outline"
                                        className={cn("rounded-full text-[10px] font-medium border shrink-0", urgency.color)}
                                    >
                                        {urgency.label}
                                    </Badge>

                                    {/* Amount */}
                                    {reminder.amount && (
                                        <span className="text-sm font-currency font-semibold text-foreground shrink-0">
                                            {formatCurrency(reminder.amount)}
                                        </span>
                                    )}
                                </div>
                            );
                        })}
                </div>
            </div>

            {/* Completed */}
            {completed.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-3">
                        <BellOff className="h-4 w-4 text-muted-foreground" />
                        <h3 className="text-sm font-semibold text-muted-foreground">Selesai</h3>
                    </div>

                    <div className="space-y-2">
                        {completed.map((reminder) => (
                            <div
                                key={reminder.id}
                                className="group flex items-center gap-3 rounded-2xl border border-primary/5 bg-gray-50/50 px-4 py-3 transition-all duration-200"
                            >
                                {/* Check done */}
                                <button
                                    onClick={() => toggleComplete(reminder.id)}
                                    className="flex h-8 w-8 shrink-0 items-center justify-center rounded-full bg-emerald-100 text-emerald-600"
                                >
                                    <Check className="h-4 w-4" />
                                </button>

                                <div className="flex-1 min-w-0">
                                    <p className="text-sm font-medium text-muted-foreground line-through">
                                        {reminder.title}
                                    </p>
                                    <span className="text-[11px] text-muted-foreground">
                                        {formatDate(reminder.dueDate)}
                                    </span>
                                </div>

                                {reminder.amount && (
                                    <span className="text-sm font-currency text-muted-foreground shrink-0">
                                        {formatCurrency(reminder.amount)}
                                    </span>
                                )}
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import { Plus, Target, Trophy, Calendar, ArrowRight } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { cn, formatCurrency } from "@/lib/utils";
import { mockSavings, mockSavingGoals } from "@/lib/mock-data";

function getGoalIcon(icon?: string): string {
    switch (icon) {
        case "ShieldCheck": return "🛡️";
        case "Plane": return "✈️";
        case "Laptop": return "💻";
        case "GraduationCap": return "🎓";
        default: return "🎯";
    }
}

export default function SavingsPage() {
    const totalSavings = mockSavings.reduce((s, v) => s + v.amount, 0);
    const activeGoals = mockSavingGoals.filter((g) => !g.isAchieved);
    const achievedGoals = mockSavingGoals.filter((g) => g.isAchieved);

    return (
        <div className="space-y-6 animate-in fade-in duration-500">
            {/* Header */}
            <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-3">
                <div>
                    <h2 className="text-xl font-bold text-foreground">
                        Tabungan & Target 🐷
                    </h2>
                    <p className="text-sm text-muted-foreground mt-1">
                        Total tabungan bulan ini{" "}
                        <span className="font-currency font-semibold text-blue-600">
                            {formatCurrency(totalSavings)}
                        </span>
                    </p>
                </div>
                <Button className="rounded-xl bg-primary hover:bg-primary/90 shadow-lg shadow-primary/25">
                    <Plus className="h-4 w-4 mr-1.5" />
                    Target Baru
                </Button>
            </div>

            {/* Monthly Savings */}
            <div className="rounded-2xl border border-primary/10 bg-white p-5">
                <div className="flex items-center gap-2 mb-4">
                    <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-blue-50">
                        <span className="text-sm">💰</span>
                    </div>
                    <div>
                        <h3 className="text-sm font-semibold text-foreground">Tabungan Bulan Ini</h3>
                        <p className="text-xs text-muted-foreground">Februari 2026</p>
                    </div>
                </div>

                <div className="space-y-2">
                    {mockSavings.map((saving) => (
                        <div
                            key={saving.id}
                            className="flex items-center justify-between rounded-xl bg-blue-50/50 px-4 py-3"
                        >
                            <div className="flex items-center gap-3">
                                <span className="text-lg">🐷</span>
                                <div>
                                    <p className="text-sm font-medium text-foreground">{saving.name}</p>
                                    <p className="text-[11px] text-muted-foreground">{saving.accountName}</p>
                                </div>
                            </div>
                            <span className="text-sm font-currency font-semibold text-blue-600">
                                {formatCurrency(saving.amount)}
                            </span>
                        </div>
                    ))}
                </div>
            </div>

            {/* Active Goals */}
            <div>
                <div className="flex items-center gap-2 mb-3">
                    <Target className="h-4 w-4 text-primary" />
                    <h3 className="text-sm font-semibold text-foreground">Target Aktif</h3>
                    <Badge variant="outline" className="rounded-full text-[10px] border-primary/20 text-primary">
                        {activeGoals.length} target
                    </Badge>
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                    {activeGoals.map((goal) => {
                        const pct = Math.round((goal.currentAmount / goal.targetAmount) * 100);
                        const remaining = goal.targetAmount - goal.currentAmount;
                        const deadline = new Date(goal.deadline);
                        const monthsLeft = Math.max(
                            0,
                            (deadline.getFullYear() - 2026) * 12 + (deadline.getMonth() + 1 - 2)
                        );

                        return (
                            <div
                                key={goal.id}
                                className="group rounded-2xl border border-primary/10 bg-white p-5 transition-all duration-300 hover:shadow-lg hover:shadow-primary/5 hover:border-primary/20"
                            >
                                {/* Icon & Title */}
                                <div className="flex items-start justify-between mb-3">
                                    <div className="flex items-center gap-2">
                                        <span className="text-2xl">{getGoalIcon(goal.icon)}</span>
                                        <div>
                                            <p className="text-sm font-semibold text-foreground">{goal.name}</p>
                                            <div className="flex items-center gap-1 mt-0.5">
                                                <Calendar className="h-3 w-3 text-muted-foreground" />
                                                <span className="text-[11px] text-muted-foreground">
                                                    {monthsLeft} bulan lagi
                                                </span>
                                            </div>
                                        </div>
                                    </div>
                                    <Badge
                                        variant="outline"
                                        className={cn(
                                            "rounded-full text-[10px] font-medium border",
                                            pct >= 60
                                                ? "bg-emerald-50 text-emerald-700 border-emerald-200"
                                                : "bg-amber-50 text-amber-700 border-amber-200"
                                        )}
                                    >
                                        {pct}%
                                    </Badge>
                                </div>

                                {/* Progress */}
                                <div className="space-y-2">
                                    <div className="h-2.5 w-full rounded-full bg-primary/10 overflow-hidden">
                                        <div
                                            className="h-full rounded-full bg-gradient-to-r from-primary to-blue-500 transition-all duration-700"
                                            style={{ width: `${pct}%` }}
                                        />
                                    </div>

                                    <div className="flex items-center justify-between">
                                        <span className="text-[11px] font-currency text-primary font-medium">
                                            {formatCurrency(goal.currentAmount)}
                                        </span>
                                        <span className="text-[11px] font-currency text-muted-foreground">
                                            {formatCurrency(goal.targetAmount)}
                                        </span>
                                    </div>

                                    <p className="text-[11px] text-muted-foreground">
                                        Kurang{" "}
                                        <span className="font-currency font-medium text-foreground">
                                            {formatCurrency(remaining)}
                                        </span>
                                        {monthsLeft > 0 && (
                                            <> • ~{formatCurrency(Math.ceil(remaining / monthsLeft))}/bulan</>
                                        )}
                                    </p>
                                </div>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Achieved Goals */}
            {achievedGoals.length > 0 && (
                <div>
                    <div className="flex items-center gap-2 mb-3">
                        <Trophy className="h-4 w-4 text-amber-500" />
                        <h3 className="text-sm font-semibold text-foreground">Target Tercapai</h3>
                    </div>

                    <div className="space-y-2">
                        {achievedGoals.map((goal) => (
                            <div
                                key={goal.id}
                                className="flex items-center justify-between rounded-xl bg-emerald-50/50 border border-emerald-100 px-4 py-3"
                            >
                                <div className="flex items-center gap-3">
                                    <span className="text-lg">{getGoalIcon(goal.icon)}</span>
                                    <div>
                                        <p className="text-sm font-medium text-foreground">{goal.name}</p>
                                        <p className="text-[11px] text-emerald-600">✓ Target tercapai</p>
                                    </div>
                                </div>
                                <span className="text-sm font-currency font-semibold text-emerald-600">
                                    {formatCurrency(goal.targetAmount)}
                                </span>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
}

"use client";

import { cn, formatCurrency } from "@/lib/utils";
import { mockIncomeSources, mockBudgets, mockSavings } from "@/lib/mock-data";

export function BudgetSummaryBar() {
    const totalIncome = mockIncomeSources.reduce((sum, s) => sum + s.amount, 0);
    const totalSavings = mockSavings.reduce((sum, s) => sum + s.amount, 0);
    const totalAllocated = mockBudgets.reduce((sum, b) => sum + b.allocation, 0);
    const remaining = totalIncome - totalAllocated;

    const cards = [
        {
            label: "Total Pemasukan",
            amount: totalIncome,
            color: "text-emerald-600",
            bg: "bg-emerald-50",
            emoji: "💰",
        },
        {
            label: "Teralokasi",
            amount: totalAllocated,
            color: "text-primary",
            bg: "bg-primary/10",
            emoji: "📋",
        },
        {
            label: "Sisa",
            amount: remaining,
            color: remaining >= 0 ? "text-emerald-600" : "text-destructive",
            bg: remaining >= 0 ? "bg-emerald-50" : "bg-red-50",
            emoji: remaining >= 0 ? "✅" : "⚠️",
        },
    ];

    return (
        <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
            {cards.map((card) => (
                <div
                    key={card.label}
                    className={cn(
                        "rounded-2xl border border-primary/10 bg-white p-4 flex items-center gap-3"
                    )}
                >
                    <div className={cn("flex h-10 w-10 items-center justify-center rounded-xl text-base", card.bg)}>
                        {card.emoji}
                    </div>
                    <div>
                        <p className="text-[11px] font-medium text-muted-foreground uppercase tracking-wider">
                            {card.label}
                        </p>
                        <p className={cn("text-lg font-bold font-currency", card.color)}>
                            {formatCurrency(card.amount)}
                        </p>
                    </div>
                </div>
            ))}
        </div>
    );
}

"use client";

import { useState } from "react";
import { Plus, Trash2, Briefcase, TrendingUp } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { cn, formatCurrency, generateId } from "@/lib/utils";
import type { IncomeSource } from "@/types";
import { mockIncomeSources } from "@/lib/mock-data";

export function IncomeSourcesForm() {
    const [sources, setSources] = useState<IncomeSource[]>(mockIncomeSources);

    const addSource = () => {
        setSources((prev) => [
            ...prev,
            { id: generateId(), name: "", type: "variable", amount: 0, month: 2, year: 2026 },
        ]);
    };

    const removeSource = (id: string) => {
        setSources((prev) => prev.filter((s) => s.id !== id));
    };

    const updateSource = (id: string, field: keyof IncomeSource, value: string | number) => {
        setSources((prev) =>
            prev.map((s) => (s.id === id ? { ...s, [field]: value } : s))
        );
    };

    const totalIncome = sources.reduce((sum, s) => sum + s.amount, 0);

    return (
        <div className="rounded-2xl border border-primary/10 bg-white p-5">
            <div className="flex items-center justify-between mb-4">
                <div className="flex items-center gap-2">
                    <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-emerald-50">
                        <Briefcase className="h-4 w-4 text-emerald-600" />
                    </div>
                    <div>
                        <h3 className="text-sm font-semibold text-foreground">Sumber Pemasukan</h3>
                        <p className="text-xs text-muted-foreground">Masukkan semua pendapatan bulan ini</p>
                    </div>
                </div>
                <span className="text-sm font-currency font-semibold text-emerald-600">
                    {formatCurrency(totalIncome)}
                </span>
            </div>

            <div className="space-y-3">
                {sources.map((source) => (
                    <div key={source.id} className="flex items-end gap-2">
                        <div className="flex-1 space-y-1">
                            <Label className="text-[11px] text-muted-foreground">Nama</Label>
                            <Input
                                value={source.name}
                                onChange={(e) => updateSource(source.id, "name", e.target.value)}
                                placeholder="Nama sumber..."
